const body = $input.first().json.body;

const customerMessage = body.Body;
const customerName = body.ProfileName;
const customerNumber = body.From;
const accountSid = body.AccountSid;

return [{
  json: {
    customerMessage,
    customerName,
    customerNumber,
    accountSid,
    groq_body: JSON.stringify({
      model: "llama-3.3-70b-versatile",
      messages: [
        {
          role: "system",
          content: `You are a helpful WhatsApp business assistant for a tech company.
You handle product inquiries and pricing questions professionally.

Our Products & Pricing:
- Basic Plan: Rs 999/month — 5 users, basic features
- Pro Plan: Rs 2499/month — 20 users, advanced features, priority support
- Enterprise Plan: Custom pricing — unlimited users, dedicated support

Rules:
-keep msg attractive and readble , so it focus on main part
- Keep replies short and conversational (WhatsApp style)
- Use simple language
- Always end with a question to keep conversation going
- If asked about something outside products/pricing, politely redirect
- Address customer by first name`
        },
        {
          role: "user",
          content: `Customer name: ${customerName}\nMessage: ${customerMessage}`
        }
      ]
    })
  }
}];

const aiReply = $('Ask Groq AI').item.json.choices[0].message.content;
const customerNumber = $('Prepare AI Request').item.json.customerNumber;
const accountSid = $('Prepare AI Request').item.json.accountSid;

// Twilio credentials
const twilioAccountSid = "SID twillo

whatsapp:+14155238886";

// Encode credentials for Basic Auth
const credentials = Buffer.from(`${twilioAccountSid}:${twilioAuthToken}`).toString('base64');
const twilio_body = `From=${encodeURIComponent(twilioNumber)}&To=${encodeURIComponent(customerNumber)}&Body=${encodeURIComponent(aiReply)}`;

return [{
  json: {
    aiReply,
    customerNumber,
    twilioAccountSid,
    credentials,
    twilioNumber,
    twilio_body
  }
}];
